// 'ad' adlı dəyişən yaradıram
var ad = 'Aysel';
console.log(ad); // nəticə: Aysel

// Dəyişənin içindəkini dəyişirəm
ad = 'Kamran';
console.log(ad); // nəticə: Kamran

// Hoisting nümunəsi
console.log(oyuncaq); // nəticə: undefined (xəta vermir!)
var oyuncaq = 'robot';
console.log(oyuncaq); // nəticə: robot

// Funksiya scope nümunəsi
function test() {
  var rəng = 'mavi';
  console.log(rəng); // nəticə: mavi
}
test();
// console.log(rəng); // Xəta: rəng is not defined, çünki funksiya xaricində işləmir

// var ilə təkrar elan etmək olar
var gadget = 'telefon';
var gadget = 'qulaqlıq';
console.log(gadget); // nəticə: qulaqlıq

// let ilə təkrar elan etmək olmaz
let içki = 'kola';
// let içki = 'su'; // Xəta: içki has already been declared

// const ilə dəyəri dəyişmək olmaz
const ad = 'Kamran';
// ad = 'Murad'; // Xəta: Assignment to constant variable

// Real həyat nümunəsi
var çanta = 'noutbuk';
console.log(çanta); // nəticə: noutbuk

// Çantanın içindəkini dəyişirəm
çanta = 'kitab';
console.log(çanta); // nəticə: kitab

// Təkrar elan edirəm, problem yoxdur
var çanta = 'qələm';
console.log(çanta); // nəticə: qələm

