// Создаём переменную 'имя' с 'Айсель'
var имя = 'Айсель';
console.log(имя); // Вывод: Айсель

// Меняем содержимое переменной
имя = 'Кямран';
console.log(имя); // Вывод: Кямран

// Пример hoisting
console.log(игрушка); // Вывод: undefined (без ошибки!)
var игрушка = 'робот';
console.log(игрушка); // Вывод: робот

// Пример области видимости функции
function тест() {
  var цвет = 'синий';
  console.log(цвет); // Вывод: синий
}
тест();
// console.log(цвет); // Ошибка: цвет не определён, так как недоступен вне функции

// Можно повторно объявить с var
var гаджет = 'телефон';
var гаджет = 'наушники';
console.log(гаджет); // Вывод: наушники

// Нельзя повторно объявить с let
let напиток = 'кола';
// let напиток = 'вода'; // Ошибка: напиток уже объявлен

// Нельзя изменить значение const
const имя = 'Кямран';
// имя = 'Мурад'; // Ошибка: Присвоение константе

// Пример из реальной жизни
var сумка = 'ноутбук';
console.log(сумка); // Вывод: ноутбук

// Меняю содержимое сумки
сумка = 'книга';
console.log(сумка); // Вывод: книга

// Повторно объявляю, нет проблем
var сумка = 'ручка';
console.log(сумка); // Вывод: ручка

